// ============================================================
// CURSOR
// ============================================================
function Cursor() {
  const c = useRef(); const d = useRef();
  useEffect(() => {
    const fn = e => {
      if(c.current){c.current.style.left=e.clientX+"px";c.current.style.top=e.clientY+"px";}
      if(d.current){d.current.style.left=e.clientX+"px";d.current.style.top=e.clientY+"px";}
    };
    window.addEventListener("mousemove",fn);
    return ()=>window.removeEventListener("mousemove",fn);
  },[]);
  return (<><div id="p3c" ref={c}/><div id="p3d" ref={d}/></>);
}

// ============================================================
// SLIDESHOW COMPONENT
// ============================================================
function Slideshow({ photos }) {
  const [idx, setIdx]       = useState(0);
  const [playing, setPlay]  = useState(true);
  const [key, setKey]       = useState(0); // force progress bar restart
  const timer = useRef();

  const go = useCallback((n) => {
    setIdx(n);
    setKey(k => k+1);
  }, []);

  const next = useCallback(() => go((idx+1) % photos.length), [idx, photos.length, go]);
  const prev = useCallback(() => go((idx-1+photos.length) % photos.length), [idx, photos.length, go]);

  useEffect(() => {
    if (!playing) return;
    timer.current = setTimeout(next, 4000);
    return () => clearTimeout(timer.current);
  }, [playing, next]);

  return (
    <div className="slideshow">
      {/* Progress bar */}
      {playing && <div className="ss-progress"><div className="ss-progress-fill" key={key}/></div>}
      <img key={idx} src={photos[idx].src} alt={photos[idx].caption} className="ss-img"/>
      <div className="ss-overlay"/>
      <div className="ss-caption">
        <div className="ss-cap-num">{String(idx+1).padStart(2,"0")} / {String(photos.length).padStart(2,"0")}</div>
        <div className="ss-cap-text">{photos[idx].caption}</div>
      </div>
      <div className="ss-controls">
        <button className="ss-btn" onClick={prev}>‹</button>
        <div className="ss-dots">
          {photos.map((_,i)=>(
            <div key={i} className={`ss-dot${i===idx?" on":""}`} onClick={()=>go(i)}/>
          ))}
        </div>
        <button className="ss-auto-btn" onClick={()=>setPlay(p=>!p)} classNamez={`ss-auto-btn${playing?" playing":""}`}>
          {playing ? "⏸ AUTO" : "▶ AUTO"}
        </button>
        <button className="ss-btn" onClick={next}>›</button>
      </div>
    </div>
  );
}

