      </div>

      {/* Chapter cards */}
      <div className="travel-chapters">
        <div className="chapters-title">「 My Story 」</div>
        <div className="chapters-grid">
          {TRAVEL.chapters.map((ch,i)=>(
            <div key={ch.title} className="chapter-card" style={{animationDelay:`${i*.08}s`}}>
              <span className="chapter-icon">{ch.icon}</span>
              <div className="chapter-title">{ch.title}</div>
              <div className="chapter-loc" style={{color:ch.color}}>📍 {ch.location}</div>
              <p className="chapter-story">{ch.story}</p>
              <div className="chapter-line" style={{background:`linear-gradient(90deg,${ch.color},transparent)`}}/>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ============================================================
// CONTACT
// ============================================================
function Contact() {
  const [form,setForm]=useState({name:"",email:"",subject:"",message:""});
  const [status,setStatus]=useState("idle");
  const ch=e=>setForm(f=>({...f,[e.target.name]:e.target.value}));
  const send=async()=>{
    if(!form.name||!form.email||!form.message)return;
    setStatus("sending");
    await new Promise(r=>setTimeout(r,1400));
    setStatus("sent");
  };
  const ls=[
    {icon:"✉",label:"Email",    val:ME.email,       href:`mailto:${ME.email}`},
    {icon:"⌥",label:"GitHub",   val:"github.com/beam",href:ME.github},
    {icon:"⊞",label:"LinkedIn", val:"linkedin/beam", href:ME.linkedin},
    {icon:"◎",label:"Location", val:ME.location,    href:"#"},
  ];
  return (
    <section className="sec">
      <div className="sec-tag">// CONNECT</div>
      <div className="sec-hd">
        <div className="sec-n">03</div>
        <div><span className="sec-ey">social links · form</span>
          <h2 className="sec-title">Get In <span className="dim">Touch</span></h2>
          <div className="sec-rule"/></div>
      </div>
      <div className="contact-layout">
        <div style={{animation:"fadeUp .5s both"}}>
          <p className="contact-lore">{ME.about}<br/><br/>Open to full-time roles, freelance, and collaborations. I respond within 24 hours.</p>
          <div className="contact-links">
            {ls.map(l=>(
              <a key={l.label} href={l.href} className="c-item" target={l.href.startsWith("http")?"_blank":undefined} rel="noreferrer">
                <div className="c-icon">{l.icon}</div>
                <div style={{flex:1}}><div className="c-lbl">{l.label}</div><div className="c-val">{l.val}</div></div>
                <span className="c-arr">›</span>
              </a>
            ))}
          </div>
        </div>
        <div style={{animation:"fadeUp .5s .2s both"}}>
          <div className="form-panel">
            {status==="sent"?(
              <div className="f-ok"><span className="f-ok-g">🌙</span><div className="f-ok-t">Message Received</div><div className="f-ok-s">Thanks, {form.name}. I'll respond within 24 hours.</div></div>
            ):(
              <>
                <div className="form-hd">「 Send a Message 」</div>
                <div className="form-2">
                  <div className="fg"><label className="fl">Name</label><input className="fi" name="name" placeholder="Jane Doe" value={form.name} onChange={ch}/></div>
                  <div className="fg"><label className="fl">Email</label><input className="fi" name="email" type="email" placeholder="jane@email.com" value={form.email} onChange={ch}/></div>
                </div>
                <div className="fg"><label className="fl">Subject</label><input className="fi" name="subject" placeholder="Project / Opportunity" value={form.subject} onChange={ch}/></div>
                <div className="fg"><label className="fl">Message</label><textarea className="fta" name="message" placeholder="Tell me about your project..." value={form.message} onChange={ch}/></div>
                <button className="f-btn" onClick={send} disabled={status==="sending"}>{status==="sending"?"TRANSMITTING...":"▶ SEND MESSAGE"}</button>
              </>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}

